class efuAI {
  constructor() {
    this.config = GLOBAL_CONFIG.post_ai; // 从配置中获取API设置
    this.aiTalkMode = false;
    this.aiPostExplanation = '';
    this.scoGPTIsRunning = false;
  }

  init() {
    if (!document.querySelector(".ai-explanation")) return;

    this.scoGPTIsRunning = false;
    this.aiPostExplanation = PAGE_CONFIG.ai_text ? PAGE_CONFIG.ai_text + "" : false;

    if (!this.aiPostExplanation) {
      this.generate();
    } else {
      this.aiShowAnimation(Promise.resolve(this.aiPostExplanation));
    }

    this.AIEngine();
  }

  getTitleAndContent() {
    const e = document.getElementById("article-container"),
          t = document.title,
          n = e.getElementsByTagName("p"),
          i = e.querySelectorAll("h1, h2, h3, h4, h5");

    return (t + " " + Array.from(i).concat(Array.from(n))
      .map((e => e.innerText.replace(/https?:\/\/[^\s]+/g, "")))
      .join(" ")).slice(0, 1000);
  }

  async generate() {
    const title = document.title;
    const content = this.getTitleAndContent();

    try {
      const explanation = await this.fetchFromChatGPT(title, content);
      this.aiShowAnimation(Promise.resolve(explanation));
    } catch (error) {
      console.error("Error generating explanation:", error);
    }
  }

  async fetchFromChatGPT(title, content) {
    const response = await fetch(this.config.apiUrl, {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${this.config.apiKey}`,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({
        model: this.config.model,
        messages: [{ role: "user", content: `${title}\n\n${content}` }],
        max_tokens: this.config.max_tokens, // 根据需要调整
      })
    });

    const data = await response.json();
    if (!response.ok) {
      throw new Error(data.error.message);
    }

    this.aiPostExplanation = data.choices[0].message.content;
    return this.aiPostExplanation;
  }

  aiShowAnimation(e, t = false) {
    const n = document.querySelector(".ai-explanation"),
          i = document.querySelector(".ai-tag");

    if (!n || this.scoGPTIsRunning) return;

    this.scoGPTIsRunning = true;
    this.cleanSuggestions();
    i.classList.add("loadingAI");
    n.style.display = "block";
    n.innerHTML = '生成中...<span class="blinking-cursor"></span>';

    let s, o, a = true, c = 0, r = true;

    const l = new IntersectionObserver((e => {
      a = e[0].isIntersecting;
      a && requestAnimationFrame(o);
    }), { threshold: 0 });

    e.then((e => {
      s = performance.now();
      o = () => {
        if (c < e.length && a) {
          const r = performance.now(),
                g = r - s,
                h = e.slice(c, c + 1),
                u = /[，。！、？,.!?]/.test(h),
                m = /[a-zA-Z0-9]/.test(h);

          g >= (u ? 100 * Math.random() + 100 : m ? 10 : 25) && 
          (n.innerText = e.slice(0, c + 1), s = r, c++, 
          c < e.length ? 
          n.innerHTML = e.slice(0, c) + '<span class="blinking-cursor"></span>' : 
          (n.innerHTML = e, n.style.display = "block", 
          this.scoGPTIsRunning = false, i.classList.remove("loadingAI"), 
          l.disconnect(), t && this.createSuggestions()));

          a && requestAnimationFrame(o);
        }
      };

      a && r && setTimeout(() => {
        requestAnimationFrame(o);
        r = false;
      }, 3000);

      l.observe(n);
    })).catch((e => {
      console.error("检索信息失败：", e);
      n.innerHTML = "检索信息失败";
      n.style.display = "block";
      this.scoGPTIsRunning = false;
      i.classList.remove("loadingAI");
      l.disconnect();
    }));
  }

  AIEngine() {
    const e = document.querySelector(".ai-tag");
    e && e.addEventListener("click", (() => {
      this.scoGPTIsRunning || 
      (this.aiTalkMode = true, 
      this.aiShowAnimation(Promise.resolve(this.config.talk), true));
    }));
  }

  cleanSuggestions() {
    const e = document.querySelector(".ai-suggestions");
    e ? e.innerHTML = "" : console.error("没有这个元素：'ai-suggestions'");
  }

  createSuggestions() {
    this.aiTalkMode && 
    (this.cleanSuggestions(), 
    this.createSuggestionItemWithAction("这篇文章讲了什么？", (() => {
      "" === this.aiPostExplanation ? 
      this.generate() : 
      this.aiShowAnimation(Promise.resolve(this.aiPostExplanation), true);
    })),
    this.config.randomPost && 
    this.createSuggestionItemWithAction("带我去看看其他文章", (() => toRandomPost())),
    this.aiTalkMode = true);
  }

  createSuggestionItemWithAction(e, t) {
    const n = document.querySelector(".ai-suggestions");

    if (!n) return void console.error("无法找到具有class为ai-suggestions的元素");

    const i = document.createElement("div");
    i.classList.add("ai-suggestions-item");
    i.textContent = e;
    i.addEventListener("click", t);
    n.appendChild(i);
  }
}

const efu_ai = new efuAI;